def _process_alive(pid: int | None) -> bool:
    """Best-effort liveness check for a job's owning process.

    Returns True when we cannot prove the process is gone (no pid recorded,
    or the platform doesn't support the probe) so we never reap a job on a
    false negative. A reliable "process is gone" is the only signal that
    lets us release a lock early regardless of the no-progress window.
    """
    if pid is None or pid <= 0:
        return True
    # A row owned by THIS process is by definition alive.
    if pid == os.getpid():
        return True
    try:
        os.kill(pid, 0)
        return True
    except ProcessLookupError:
        return False
    except PermissionError:
        # Process exists but is owned by another user — treat as alive.
        return True
    except OSError:
        return True

def _require_conn() -> sqlite3.Connection:
    if _conn is None:
        raise RuntimeError(
            "jobs_store.init() must be called before any other DAO function"
        )
    return _conn

def _row_get(row: sqlite3.Row, key: str) -> str | None:
    """Safe column-fetch — returns None when the column is missing.

    ``sqlite3.Row`` raises ``IndexError`` if the key isn't in the cursor
    description, so we trap that and treat it as ``None``. Lets us add
    columns over time without breaking callers that fetched rows before
    the migration ran.
    """
    try:
        val = row[key]
    except (IndexError, KeyError):
        return None
    if val is None:
        return None
    return str(val)

